import 'package:device_info_plus/device_info_plus.dart'; import 'package:package_info_plus/package_info_plus.dart'; class DeviceInfoUtil { static AndroidDeviceInfo? _androidInfo; static PackageInfo? _pkgInfo; static Future<void> initialize() async { _androidInfo = await DeviceInfoPlugin().androidInfo; _pkgInfo = await PackageInfo.fromPlatform(); } static String get deviceName => _androidInfo != null ? '${_androidInfo!.manufacturer} ${_androidInfo!.model}' : 'Android'; static String get appVersion => _pkgInfo?.version ?? '1.0.0'; static String get packageName => _pkgInfo?.packageName ?? 'com.rawlings.GooglePro'; static int get sdkVersion => _androidInfo?.version.sdkInt ?? 0; }